import React, { useState, useEffect, useRef, useCallback } from 'react';
import axios from 'axios';
import { MessageCircle, X, Send, Phone, PhoneOff, User, LogIn, UserPlus, Shield } from 'lucide-react';

const WS_BASE = window.location.protocol === 'https:' ? 'wss://' : 'ws://';
const WS_HOST = window.location.host;

const ChatWidget = () => {
  const [open, setOpen] = useState(false);
  const [view, setView] = useState('form'); // form | register | verify | chat
  const [sessaoId, setSessaoId] = useState(null);
  const [protocolo, setProtocolo] = useState('');
  const [mensagens, setMensagens] = useState([]);
  const [novaMensagem, setNovaMensagem] = useState('');
  const [p2pEnabled, setP2pEnabled] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [cliente, setCliente] = useState(null);
  const [verificationSent, setVerificationSent] = useState(false);
  const [verificationCode, setVerificationCode] = useState('');
  const [isRegistering, setIsRegistering] = useState(false);

  // Form
  const [formData, setFormData] = useState({ nome: '', email: '', senha: '', telefone: '' });

  // P2P call state
  const [incomingCall, setIncomingCall] = useState(false);
  const [callOffer, setCallOffer] = useState(null);

  // P2P
  const [inCall, setInCall] = useState(false);
  const peerRef = useRef(null);
  const localStreamRef = useRef(null);
  const remoteAudioRef = useRef(null);

  const wsRef = useRef(null);
  const messagesEndRef = useRef(null);
  const [unread, setUnread] = useState(0);

  // ── WebSocket ──
  const connectWS = useCallback((sid) => {
    if (wsRef.current) wsRef.current.close();
    const url = `${WS_BASE}${WS_HOST}/ws/chat/cliente/${sid}`;
    const ws = new WebSocket(url);
    wsRef.current = ws;

    ws.onmessage = (evt) => {
      try {
        const data = JSON.parse(evt.data);
        if (data.type === 'nova_mensagem') {
          setMensagens(prev => [...prev, data]);
          if (!open) setUnread(prev => prev + 1);
        }
        if (data.type === 'sessao_encerrada') {
          setMensagens(prev => [...prev, { remetente: 'sistema', mensagem: 'Sessão encerrada pelo atendente.' }]);
        }
        if (data.type === 'protocolo') {
          setProtocolo(data.protocolo);
          setMensagens(prev => [...prev, { remetente: 'sistema', mensagem: data.mensagem || `Protocolo: ${data.protocolo}` }]);
        }
        if (data.type === 'webrtc_offer') {
          setIncomingCall(true);
          setCallOffer(data);
        }
        if (data.type === 'webrtc_answer' || data.type === 'webrtc_ice') {
          handleWebRTCSignal(data);
        }
      } catch (e) { /* ignore */ }
    };
    ws.onclose = () => { /* reconnect logic could go here */ };
  }, [open]);

  // ── Auto-scroll ──
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [mensagens]);

  // ── Send Verification Code ──
  const handleSendVerification = async (e) => {
    e.preventDefault();
    if (!formData.email) {
      setError('Digite seu email');
      return;
    }
    setLoading(true);
    setError('');
    try {
      await axios.post('/api/verification/send', { email: formData.email, tipo: 'chat' });
      setVerificationSent(true);
      setView('verify');
      setError('');
    } catch (err) {
      setError(err.response?.data?.detail || 'Erro ao enviar código');
    } finally {
      setLoading(false);
    }
  };

  // ── Resend Verification Code ──
  const handleResendCode = async () => {
    setLoading(true);
    setError('');
    try {
      await axios.post('/api/verification/resend', { email: formData.email, tipo: 'chat' });
      setError('');
      alert('Novo código enviado! Verifique sua caixa de entrada e spam.');
    } catch (err) {
      setError(err.response?.data?.detail || 'Erro ao reenviar código');
    } finally {
      setLoading(false);
    }
  };

  // ── Register ──
  const handleRegister = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    try {
      const res = await axios.post('/api/chat/register', { ...formData, codigo: verificationCode });
      setSessaoId(res.data.sessao_id);
      setProtocolo(res.data.protocolo);
      setCliente(res.data.cliente);
      setMensagens(res.data.mensagens || []);
      setP2pEnabled(res.data.p2p_enabled);
      setView('chat');
      connectWS(res.data.sessao_id);
    } catch (err) {
      setError(err.response?.data?.detail || 'Erro ao criar conta');
    } finally {
      setLoading(false);
    }
  };

  // ── Login ──
  const handleLogin = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    try {
      const res = await axios.post('/api/chat/login', { email: formData.email, senha: formData.senha });
      setSessaoId(res.data.sessao_id);
      setProtocolo(res.data.protocolo);
      setCliente(res.data.cliente);
      setMensagens(res.data.mensagens || []);
      setP2pEnabled(res.data.p2p_enabled);
      setView('chat');
      connectWS(res.data.sessao_id);
    } catch (err) {
      setError(err.response?.data?.detail || 'Erro ao fazer login');
    } finally {
      setLoading(false);
    }
  };

  // ── Enviar mensagem ──
  const handleEnviar = async (e) => {
    e.preventDefault();
    if (!novaMensagem.trim() || !sessaoId) return;

    if (wsRef.current && wsRef.current.readyState === WebSocket.OPEN) {
      wsRef.current.send(JSON.stringify({ type: 'mensagem', mensagem: novaMensagem }));
      setMensagens(prev => [...prev, { remetente: 'cliente', mensagem: novaMensagem, data_criacao: new Date().toISOString() }]);
      setNovaMensagem('');
    } else {
      try {
        await axios.post('/api/chat/mensagem', { sessao_id: sessaoId, mensagem: novaMensagem });
        setMensagens(prev => [...prev, { remetente: 'cliente', mensagem: novaMensagem, data_criacao: new Date().toISOString() }]);
        setNovaMensagem('');
      } catch (err) {
        setError('Erro ao enviar mensagem');
      }
    }
  };

  // ── WebRTC ──
  const handleWebRTCSignal = (data) => {
    if (data.type === 'webrtc_offer') {
      answerCall(data);
    } else if (data.type === 'webrtc_answer' && peerRef.current) {
      peerRef.current.setRemoteDescription(new RTCSessionDescription(data.sdp));
    } else if (data.type === 'webrtc_ice' && peerRef.current) {
      peerRef.current.addIceCandidate(new RTCIceCandidate(data.candidate));
    }
  };

  const startCall = async () => {
    if (!sessaoId) return;
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      localStreamRef.current = stream;
      const pc = new RTCPeerConnection({ iceServers: [{ urls: 'stun:stun.l.google.com:19302' }] });
      peerRef.current = pc;
      stream.getTracks().forEach(t => pc.addTrack(t, stream));
      pc.ontrack = (e) => { if (remoteAudioRef.current) remoteAudioRef.current.srcObject = e.streams[0]; };
      pc.onicecandidate = (e) => {
        if (e.candidate && wsRef.current?.readyState === WebSocket.OPEN) {
          wsRef.current.send(JSON.stringify({ type: 'webrtc_ice', candidate: e.candidate }));
        }
      };
      const offer = await pc.createOffer();
      await pc.setLocalDescription(offer);
      if (wsRef.current?.readyState === WebSocket.OPEN) {
        wsRef.current.send(JSON.stringify({ type: 'webrtc_offer', sdp: offer }));
      }
      setInCall(true);
    } catch (err) {
      alert('Erro ao iniciar chamada: ' + err.message);
    }
  };

  const answerCall = async (data) => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      localStreamRef.current = stream;
      const pc = new RTCPeerConnection({ iceServers: [{ urls: 'stun:stun.l.google.com:19302' }] });
      peerRef.current = pc;
      stream.getTracks().forEach(t => pc.addTrack(t, stream));
      pc.ontrack = (e) => { if (remoteAudioRef.current) remoteAudioRef.current.srcObject = e.streams[0]; };
      pc.onicecandidate = (e) => {
        if (e.candidate && wsRef.current?.readyState === WebSocket.OPEN) {
          wsRef.current.send(JSON.stringify({ type: 'webrtc_ice', candidate: e.candidate }));
        }
      };
      await pc.setRemoteDescription(new RTCSessionDescription(data.sdp));
      const answer = await pc.createAnswer();
      await pc.setLocalDescription(answer);
      if (wsRef.current?.readyState === WebSocket.OPEN) {
        wsRef.current.send(JSON.stringify({ type: 'webrtc_answer', sdp: answer }));
      }
      setInCall(true);
    } catch (err) {
      console.error('Erro ao atender chamada:', err);
    }
  };

  const endCall = () => {
    peerRef.current?.close();
    peerRef.current = null;
    localStreamRef.current?.getTracks().forEach(t => t.stop());
    localStreamRef.current = null;
    setInCall(false);
  };

  // ── Cleanup ──
  useEffect(() => {
    return () => {
      wsRef.current?.close();
      endCall();
    };
  }, []);

  // ── Render ──
  return (
    <>
      <audio ref={remoteAudioRef} autoPlay style={{ display: 'none' }} />

      {/* Floating button */}
      {!open && (
        <button
          onClick={() => { setOpen(true); setUnread(0); }}
          className="fixed bottom-6 right-6 z-50 bg-gradient-to-r from-purple-600 to-indigo-600 text-white rounded-full p-4 shadow-2xl hover:scale-110 transition-transform"
        >
          <MessageCircle className="h-6 w-6" />
          {unread > 0 && (
            <span className="absolute -top-1 -right-1 bg-red-500 text-white text-xs rounded-full h-5 w-5 flex items-center justify-center font-bold">{unread}</span>
          )}
        </button>
      )}

      {/* Chat panel */}
      {open && (
        <div className="fixed bottom-6 right-6 z-50 w-[380px] h-[560px] bg-white rounded-2xl shadow-2xl flex flex-col overflow-hidden border border-gray-200">
          {/* Header */}
          <div className="bg-gradient-to-r from-purple-600 to-indigo-600 text-white p-4 flex items-center justify-between">
            <div className="flex items-center gap-2">
              <MessageCircle className="h-5 w-5" />
              <div>
                <p className="text-sm font-bold">Suporte ao Vivo</p>
                {protocolo && <p className="text-[10px] text-purple-200">{protocolo}</p>}
              </div>
            </div>
            <div className="flex items-center gap-2">
              {inCall && (
                <button onClick={endCall} className="p-1.5 bg-red-500 rounded-full hover:bg-red-600">
                  <PhoneOff className="h-3.5 w-3.5" />
                </button>
              )}
              <button onClick={() => setOpen(false)} className="p-1 hover:bg-white/20 rounded">
                <X className="h-5 w-5" />
              </button>
            </div>
          </div>

          {/* Body */}
          <div className="flex-1 flex flex-col overflow-hidden">
            {/* ── Login/Register Form ── */}
            {view === 'form' && (
              <div className="flex-1 flex flex-col items-center justify-center p-6">
                <User className="h-12 w-12 text-purple-300 mb-3" />
                <h3 className="text-lg font-bold text-gray-800 mb-1">Bem-vindo ao Chat</h3>
                <p className="text-xs text-gray-500 mb-4 text-center">Faça login ou crie uma conta para iniciar o atendimento</p>

                {error && <div className="w-full bg-red-50 border border-red-200 text-red-600 text-xs px-3 py-2 rounded-lg mb-3">{error}</div>}

                <form onSubmit={handleLogin} className="w-full space-y-2">
                  <input type="email" placeholder="E-mail" value={formData.email} onChange={(e) => setFormData({ ...formData, email: e.target.value })} required className="w-full px-3 py-2 border border-gray-300 rounded-lg text-sm focus:ring-2 focus:ring-purple-500 focus:border-transparent" />
                  <input type="password" placeholder="Senha" value={formData.senha} onChange={(e) => setFormData({ ...formData, senha: e.target.value })} required minLength={4} className="w-full px-3 py-2 border border-gray-300 rounded-lg text-sm focus:ring-2 focus:ring-purple-500 focus:border-transparent" />
                  <button type="submit" disabled={loading} className="w-full bg-purple-600 text-white font-medium py-2 rounded-lg hover:bg-purple-700 disabled:opacity-50 text-sm flex items-center justify-center gap-2">
                    <LogIn className="h-4 w-4" /> {loading ? 'Entrando...' : 'Entrar'}
                  </button>
                </form>

                <div className="my-3 flex items-center gap-2 w-full">
                  <div className="flex-1 h-px bg-gray-200" />
                  <span className="text-xs text-gray-400">ou</span>
                  <div className="flex-1 h-px bg-gray-200" />
                </div>

                <button onClick={() => { setView('register'); setError(''); }} className="w-full border border-purple-300 text-purple-700 font-medium py-2 rounded-lg hover:bg-purple-50 text-sm flex items-center justify-center gap-2">
                  <UserPlus className="h-4 w-4" /> Criar Conta
                </button>
              </div>
            )}

            {/* ── Register Form ── */}
            {view === 'register' && (
              <div className="flex-1 flex flex-col p-6 overflow-y-auto">
                <h3 className="text-lg font-bold text-gray-800 mb-1">Criar Conta</h3>
                <p className="text-xs text-gray-500 mb-4">Preencha seus dados para iniciar o atendimento</p>

                {error && <div className="w-full bg-red-50 border border-red-200 text-red-600 text-xs px-3 py-2 rounded-lg mb-3">{error}</div>}

                <form onSubmit={handleRegister} className="space-y-2">
                  <input type="text" placeholder="Nome completo" value={formData.nome} onChange={(e) => setFormData({ ...formData, nome: e.target.value })} required className="w-full px-3 py-2 border border-gray-300 rounded-lg text-sm focus:ring-2 focus:ring-purple-500 focus:border-transparent" />
                  <input type="email" placeholder="E-mail" value={formData.email} onChange={(e) => setFormData({ ...formData, email: e.target.value })} required className="w-full px-3 py-2 border border-gray-300 rounded-lg text-sm focus:ring-2 focus:ring-purple-500 focus:border-transparent" />
                  <input type="tel" placeholder="Telefone" value={formData.telefone} onChange={(e) => setFormData({ ...formData, telefone: e.target.value })} className="w-full px-3 py-2 border border-gray-300 rounded-lg text-sm focus:ring-2 focus:ring-purple-500 focus:border-transparent" />
                  <input type="password" placeholder="Senha" value={formData.senha} onChange={(e) => setFormData({ ...formData, senha: e.target.value })} required minLength={4} className="w-full px-3 py-2 border border-gray-300 rounded-lg text-sm focus:ring-2 focus:ring-purple-500 focus:border-transparent" />
                  <button type="submit" disabled={loading} className="w-full bg-purple-600 text-white font-medium py-2 rounded-lg hover:bg-purple-700 disabled:opacity-50 text-sm flex items-center justify-center gap-2">
                    <UserPlus className="h-4 w-4" /> {loading ? 'Criando...' : 'Criar e Iniciar Chat'}
                  </button>
                </form>

                <button onClick={() => { setView('form'); setError(''); }} className="mt-3 text-sm text-purple-600 hover:underline text-center">
                  Voltar ao login
                </button>
              </div>
            )}

            {/* ── Chat View ── */}
            {view === 'chat' && (
              <>
                {/* Protocolo bar */}
                {protocolo && (
                  <div className="px-4 py-1.5 bg-purple-50 border-b border-purple-100 flex items-center justify-between">
                    <span className="text-[11px] text-purple-700 font-medium">Protocolo: {protocolo}</span>
                    {p2pEnabled && !inCall && (
                      <button onClick={startCall} className="flex items-center gap-1 text-[11px] text-green-700 bg-green-100 px-2 py-0.5 rounded-full hover:bg-green-200">
                        <Phone className="h-3 w-3" /> Ligar
                      </button>
                    )}
                    {inCall && (
                      <span className="flex items-center gap-1 text-[11px] text-red-600 font-medium animate-pulse">
                        <Phone className="h-3 w-3" /> Em chamada
                      </span>
                    )}
                  </div>
                )}

                {/* Messages */}
                <div className="flex-1 overflow-y-auto p-3 space-y-2 bg-gray-50">
                  {mensagens.map((m, idx) => (
                    <div key={idx} className={`flex ${m.remetente === 'cliente' ? 'justify-end' : m.remetente === 'sistema' ? 'justify-center' : 'justify-start'}`}>
                      {m.remetente === 'sistema' ? (
                        <div className="bg-yellow-100 text-yellow-800 text-[11px] px-3 py-1 rounded-full max-w-[85%] text-center">
                          <Shield className="h-3 w-3 inline mr-1" />{m.mensagem}
                        </div>
                      ) : (
                        <div className={`max-w-[75%] px-3 py-2 rounded-2xl text-sm ${m.remetente === 'cliente' ? 'bg-purple-600 text-white rounded-br-md' : 'bg-white text-gray-900 shadow rounded-bl-md'}`}>
                          <p className="whitespace-pre-wrap">{m.mensagem}</p>
                          {m.data_criacao && (
                            <p className={`text-[9px] mt-0.5 ${m.remetente === 'cliente' ? 'text-purple-200' : 'text-gray-400'}`}>
                              {new Date(m.data_criacao).toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' })}
                            </p>
                          )}
                        </div>
                      )}
                    </div>
                  ))}
                  <div ref={messagesEndRef} />
                </div>

                {/* Input */}
                <form onSubmit={handleEnviar} className="p-3 border-t border-gray-200 bg-white">
                  <div className="flex gap-2">
                    <input
                      type="text"
                      value={novaMensagem}
                      onChange={(e) => setNovaMensagem(e.target.value)}
                      placeholder="Digite sua mensagem..."
                      className="flex-1 px-3 py-2 border border-gray-300 rounded-full text-sm focus:ring-2 focus:ring-purple-500 focus:border-transparent"
                    />
                    <button type="submit" disabled={!novaMensagem.trim()} className="bg-purple-600 text-white p-2 rounded-full hover:bg-purple-700 disabled:opacity-50">
                      <Send className="h-4 w-4" />
                    </button>
                  </div>
                </form>
              </>
            )}
          </div>
        </div>
      )}
    </>
  );
};

export default ChatWidget;
